import{_ as o,H as r,f as l,i as a}from"./chunks/framework.DLd0CbzH.js";const i=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"interview/react.md","filePath":"interview/react.md","lastUpdated":null}'),n={name:"interview/react.md"};function t(e,s,p,c,g,b){return r(),l("div",null,[...s[0]||(s[0]=[a('<h3 id="_1-react-为什么要使用-virtual-dom-它解决了什么问题" tabindex="-1"><span style="color:rgb(15, 17, 21);">1. React 为什么要使用 Virtual DOM？它解决了什么问题？</span> <a class="header-anchor" href="#_1-react-为什么要使用-virtual-dom-它解决了什么问题" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;1. React 为什么要使用 Virtual DOM？它解决了什么问题？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">直接操作 DOM 的性能瓶颈</span></strong><span style="color:rgb(15, 17, 21);">：真实 DOM 操作代价高昂，频繁的读写会导致浏览器反复重排重绘。</span></li><li><strong><span style="color:rgb(15, 17, 21);">抽象与解耦</span></strong><span style="color:rgb(15, 17, 21);">：虚拟 DOM 是 UI 的轻量级 JavaScript 描述对象，让 React 可以不依赖具体 DOM 环境运行（如 SSR、React Native）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">批量与最小化更新</span></strong><span style="color:rgb(15, 17, 21);">：通过 Diff 算法找出最小变更集，再一次性提交到真实 DOM，避免不必要的 DOM 操作。</span></li><li><strong><span style="color:rgb(15, 17, 21);">跨平台能力</span></strong><span style="color:rgb(15, 17, 21);">：虚拟 DOM 这一抽象层让同一套核心逻辑可以渲染到 Web、Native、Canvas 等多种目标平台。</span></li></ul><h3 id="_2-react-diff-算法原理" tabindex="-1"><span style="color:rgb(15, 17, 21);">2. React Diff 算法原理？</span> <a class="header-anchor" href="#_2-react-diff-算法原理" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;2. React Diff 算法原理？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong><span style="color:rgb(15, 17, 21);"><br></span><span style="color:rgb(15, 17, 21);">Diff 算法基于三个策略假设将时间复杂度从 O(n³) 降至 O(n)：</span></p><ul><li><strong><span style="color:rgb(15, 17, 21);">Tree Diff（分层比较）</span></strong><span style="color:rgb(15, 17, 21);">：只对同层节点进行比较，跨层级移动直接删除+创建，不尝试复用。</span></li><li><strong><span style="color:rgb(15, 17, 21);">Component Diff（类型比较）</span></strong><span style="color:rgb(15, 17, 21);">：相同类型的组件继续 Diff，类型不同则直接卸载旧组件、挂载新组件。</span></li><li><strong><span style="color:rgb(15, 17, 21);">Element Diff（同级列表比较）</span></strong><span style="color:rgb(15, 17, 21);">：对同一层级的子节点，通过</span><span style="color:rgb(15, 17, 21);"></span><code>key</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">来进行唯一标识，执行插入、移动、删除操作。React 会优先匹配</span><span style="color:rgb(15, 17, 21);"></span><code>key</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">相同的节点进行复用和位移。</span></li></ul><h3 id="_3-key-为什么不能用-index" tabindex="-1"><span style="color:rgb(15, 17, 21);">3. key 为什么不能用 index？</span> <a class="header-anchor" href="#_3-key-为什么不能用-index" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;3. key 为什么不能用 index？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">当列表发生添加、删除、排序操作时，使用</span><span style="color:rgb(15, 17, 21);"></span><code>index</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">作为</span><span style="color:rgb(15, 17, 21);"></span><code>key</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">会导致同一个</span><span style="color:rgb(15, 17, 21);"></span><code>key</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">对应的元素内容发生变化，React 会认为这是同一个组件的更新而不会正确地移动或重建 DOM。</span></li><li><span style="color:rgb(15, 17, 21);">这会引发</span><strong><span style="color:rgb(15, 17, 21);">状态错乱</span></strong><span style="color:rgb(15, 17, 21);">（如非受控组件的输入框内容未跟随数据）、</span><strong><span style="color:rgb(15, 17, 21);">不必要的 DOM 更新</span></strong><span style="color:rgb(15, 17, 21);">（本该被删除的节点被复用更新），降低 Diff 效率。</span></li><li><span style="color:rgb(15, 17, 21);">正确的</span><span style="color:rgb(15, 17, 21);"></span><code>key</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">应当是数据的稳定唯一标识，让 React 能够精确定位新旧集合中节点的映射关系。</span></li></ul><h3 id="_4-react-生命周期-类组件与-hooks-对比" tabindex="-1"><span style="color:rgb(15, 17, 21);">4. React 生命周期（类组件与 hooks 对比）</span> <a class="header-anchor" href="#_4-react-生命周期-类组件与-hooks-对比" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;4. React 生命周期（类组件与 hooks 对比）&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">挂载阶段</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><span style="color:rgb(15, 17, 21);">类组件：</span><code>constructor</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">→</span><span style="color:rgb(15, 17, 21);"></span><code>getDerivedStateFromProps</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">→</span><span style="color:rgb(15, 17, 21);"></span><code>render</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">→</span><span style="color:rgb(15, 17, 21);"></span><code>componentDidMount</code></li><li><span style="color:rgb(15, 17, 21);">Hooks：</span><code>useState/useReducer</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">→ 组件函数体 → 带空依赖</span><span style="color:rgb(15, 17, 21);"></span><code>useEffect</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">模拟</span><span style="color:rgb(15, 17, 21);"></span><code>componentDidMount</code></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">更新阶段</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><span style="color:rgb(15, 17, 21);">类组件：</span><code>getDerivedStateFromProps</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">→</span><span style="color:rgb(15, 17, 21);"></span><code>shouldComponentUpdate</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">→</span><span style="color:rgb(15, 17, 21);"></span><code>render</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">→</span><span style="color:rgb(15, 17, 21);"></span><code>getSnapshotBeforeUpdate</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">→</span><span style="color:rgb(15, 17, 21);"></span><code>componentDidUpdate</code></li><li><span style="color:rgb(15, 17, 21);">Hooks：组件函数体重新执行，</span><code>useEffect</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">根据依赖变化执行清理与副作用</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">卸载阶段</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><span style="color:rgb(15, 17, 21);">类组件：</span><code>componentWillUnmount</code></li><li><span style="color:rgb(15, 17, 21);">Hooks：在</span><span style="color:rgb(15, 17, 21);"></span><code>useEffect</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">的清理函数中执行</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">思维变化</span></strong><span style="color:rgb(15, 17, 21);">：Hooks 将关注点从“生命周期时刻”转向“状态与副作用同步”，更符合函数式编程思想。</span></li></ul><h3 id="_5-setstate-为什么是异步" tabindex="-1"><span style="color:rgb(15, 17, 21);">5. setState 为什么是异步？</span> <a class="header-anchor" href="#_5-setstate-为什么是异步" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;5. setState 为什么是异步？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">性能优化</span></strong><span style="color:rgb(15, 17, 21);">：React 会将一段同步代码块内的多次</span><span style="color:rgb(15, 17, 21);"></span><code>setState</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">合并为一次更新（批量更新），减少不必要的 Render 次数。</span></li><li><strong><span style="color:rgb(15, 17, 21);">内部一致性</span></strong><span style="color:rgb(15, 17, 21);">：在合成事件、生命周期函数中保持 state、props 的同步更新。如果同步执行，在</span><span style="color:rgb(15, 17, 21);"></span><code>setState</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">前后读取的 state 可能不一致。</span></li><li><strong><span style="color:rgb(15, 17, 21);">React 18 自动批处理</span></strong><span style="color:rgb(15, 17, 21);">：在 18 中，通过</span><span style="color:rgb(15, 17, 21);"></span><code>createRoot</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">挂载的应用中，在 setTimeout、Promise、原生事件等异步回调里也会自动批处理，这进一步扩大了批量更新的场景。</span></li></ul><h3 id="_6-react-事件机制-合成事件" tabindex="-1"><span style="color:rgb(15, 17, 21);">6. React 事件机制（合成事件）</span> <a class="header-anchor" href="#_6-react-事件机制-合成事件" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;6. React 事件机制（合成事件）&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">事件委托</span></strong><span style="color:rgb(15, 17, 21);">：React 并不将事件直接绑定到具体 DOM 节点上，而是在</span><span style="color:rgb(15, 17, 21);"></span><code>root</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">节点上统一监听所有事件。</span></li><li><strong><span style="color:rgb(15, 17, 21);">合成事件对象</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>SyntheticEvent</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">是对浏览器原生事件的跨浏览器封装，提供统一 API。</span></li><li><strong><span style="color:rgb(15, 17, 21);">事件池</span></strong><span style="color:rgb(15, 17, 21);">（React 16 及以前）：事件对象会被回收复用，因此异步使用需调用</span><span style="color:rgb(15, 17, 21);"></span><code>event.persist()</code><span style="color:rgb(15, 17, 21);">。React 17 以后移除事件池。</span></li><li><strong><span style="color:rgb(15, 17, 21);">目的</span></strong><span style="color:rgb(15, 17, 21);">：保证跨浏览器一致性、优化内存占用、方便做诸如批量更新等框架层控制。</span></li></ul><h3 id="_7-react-中状态提升怎么理解" tabindex="-1"><span style="color:rgb(15, 17, 21);">7. React 中状态提升怎么理解？</span> <a class="header-anchor" href="#_7-react-中状态提升怎么理解" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;7. React 中状态提升怎么理解？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">当两个不相连的兄弟组件需要共享同一份状态时，应将状态提到它们最近的共同祖先组件中。</span></li><li><span style="color:rgb(15, 17, 21);">祖先组件将状态值和修改状态的方法通过</span><span style="color:rgb(15, 17, 21);"></span><code>props</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">分别下发给两个子组件，实现数据共享。</span></li><li><span style="color:rgb(15, 17, 21);">这也是“单向数据流”原则的体现，避免多个组件各自维护同步状态导致不一致。</span></li></ul><h3 id="_8-controlled-与-uncontrolled-component" tabindex="-1"><span style="color:rgb(15, 17, 21);">8. controlled 与 uncontrolled component</span> <a class="header-anchor" href="#_8-controlled-与-uncontrolled-component" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;8. controlled 与 uncontrolled component&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">受控组件</span></strong><span style="color:rgb(15, 17, 21);">：表单输入的值由 React 组件的 state 完全控制（</span><code>value={this.state.value}</code><span style="color:rgb(15, 17, 21);">），每次输入变化通过</span><span style="color:rgb(15, 17, 21);"></span><code>onChange</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">更新 state。React 是“唯一数据源”。</span></li><li><strong><span style="color:rgb(15, 17, 21);">非受控组件</span></strong><span style="color:rgb(15, 17, 21);">：表单数据由 DOM 自身维护，React 通过</span><span style="color:rgb(15, 17, 21);"></span><code>ref</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">在需要时读取其值，不实时控制其展示。</span></li><li><strong><span style="color:rgb(15, 17, 21);">选择依据</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><span style="color:rgb(15, 17, 21);">受控：需即时校验、动态 UI 反馈、与其它 UI 状态联动时使用。</span></li><li><span style="color:rgb(15, 17, 21);">非受控：简单表单、文件上传、集成非 React 代码等场景。</span></li></ul></li></ul><h3 id="_9-react-如何实现组件通信" tabindex="-1"><span style="color:rgb(15, 17, 21);">9. React 如何实现组件通信？</span> <a class="header-anchor" href="#_9-react-如何实现组件通信" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;9. React 如何实现组件通信？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">父传子</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>props</code></li><li><strong><span style="color:rgb(15, 17, 21);">子传父</span></strong><span style="color:rgb(15, 17, 21);">：父组件传递回调函数给子组件调用</span></li><li><strong><span style="color:rgb(15, 17, 21);">兄弟组件</span></strong><span style="color:rgb(15, 17, 21);">：状态提升到共同父组件</span></li><li><strong><span style="color:rgb(15, 17, 21);">跨层级</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>Context</code><span style="color:rgb(15, 17, 21);">（Provider/Consumer 或</span><span style="color:rgb(15, 17, 21);"></span><code>useContext</code><span style="color:rgb(15, 17, 21);">）</span></li><li><strong><span style="color:rgb(15, 17, 21);">全局状态管理</span></strong><span style="color:rgb(15, 17, 21);">：Redux、MobX、Zustand 等</span></li><li><strong><span style="color:rgb(15, 17, 21);">发布订阅</span></strong><span style="color:rgb(15, 17, 21);">：使用 EventEmitter 或自定义事件总线（较少推荐）</span></li><li><strong><span style="color:rgb(15, 17, 21);">ref</span></strong><span style="color:rgb(15, 17, 21);">：父组件通过</span><span style="color:rgb(15, 17, 21);"></span><code>ref</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">获取子组件实例或暴露的方法（</span><code>useImperativeHandle</code><span style="color:rgb(15, 17, 21);">）</span></li></ul><h3 id="_10-react-router-原理" tabindex="-1"><span style="color:rgb(15, 17, 21);">10. React Router 原理</span> <a class="header-anchor" href="#_10-react-router-原理" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;10. React Router 原理&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">基于</span><span style="color:rgb(15, 17, 21);"></span><strong><span style="color:rgb(15, 17, 21);">History API</span></strong><span style="color:rgb(15, 17, 21);">（</span><code>pushState</code><span style="color:rgb(15, 17, 21);">、</span><code>popstate</code><span style="color:rgb(15, 17, 21);">）和</span><span style="color:rgb(15, 17, 21);"></span><code>hashchange</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">事件监听 URL 变化。</span></li><li><span style="color:rgb(15, 17, 21);">内部维护一个</span><strong><span style="color:rgb(15, 17, 21);">路由匹配栈</span></strong><span style="color:rgb(15, 17, 21);">，将当前 URL 与配置的</span><span style="color:rgb(15, 17, 21);"></span><code>Route</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">进行匹配，渲染匹配到的组件。</span></li><li><code>&lt;BrowserRouter&gt;</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">使用 HTML5 History 模式，</span><code>&lt;HashRouter&gt;</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">使用 Hash 模式。</span></li><li><span style="color:rgb(15, 17, 21);">通过</span><span style="color:rgb(15, 17, 21);"></span><code>Link</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">组件阻止默认跳转，调用 History 的</span><span style="color:rgb(15, 17, 21);"></span><code>push/replace</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">更新 URL，触发生成的历史记录变化后，Router 重新匹配渲染。</span></li></ul><hr><h2 id="第二部分-hooks-深度-10题" tabindex="-1"><span style="color:rgb(15, 17, 21);">第二部分：Hooks 深度（10题）</span> <a class="header-anchor" href="#第二部分-hooks-深度-10题" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;第二部分：Hooks 深度（10题）&lt;/span&gt;&quot;">​</a></h2><h3 id="_1-hooks-为什么不能写在条件判断里" tabindex="-1"><span style="color:rgb(15, 17, 21);">1. hooks 为什么不能写在条件判断里？</span> <a class="header-anchor" href="#_1-hooks-为什么不能写在条件判断里" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;1. hooks 为什么不能写在条件判断里？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">React 依赖 Hook 的</span><strong><span style="color:rgb(15, 17, 21);">调用顺序</span></strong><span style="color:rgb(15, 17, 21);">来正确关联每次渲染中的状态和副作用。</span></li><li><span style="color:rgb(15, 17, 21);">每个组件的所有 Hooks 在 Fiber 节点上以</span><strong><span style="color:rgb(15, 17, 21);">链表</span></strong><span style="color:rgb(15, 17, 21);">形式存储，渲染时按顺序遍历链表。</span></li><li><span style="color:rgb(15, 17, 21);">如果某次渲染跳过了某个 Hook，会导致顺序错位，后续 Hook 的 state 和 effect 全部错乱。</span></li><li><span style="color:rgb(15, 17, 21);">因此 React 要求 Hooks 必须在函数顶层调用，以保证每次渲染时调用顺序恒定。</span></li></ul><h3 id="_2-useeffect-和-uselayouteffect-区别" tabindex="-1"><span style="color:rgb(15, 17, 21);">2. useEffect 和 useLayoutEffect 区别？</span> <a class="header-anchor" href="#_2-useeffect-和-uselayouteffect-区别" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;2. useEffect 和 useLayoutEffect 区别？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">执行时机</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><code>useEffect</code><span style="color:rgb(15, 17, 21);">：在浏览器</span><strong><span style="color:rgb(15, 17, 21);">完成布局与绘制之后</span></strong><span style="color:rgb(15, 17, 21);">异步执行，不会阻塞页面渲染。</span></li><li><code>useLayoutEffect</code><span style="color:rgb(15, 17, 21);">：在 DOM 变更之后、浏览器绘制</span><strong><span style="color:rgb(15, 17, 21);">之前</span></strong><span style="color:rgb(15, 17, 21);">同步执行，会阻塞绘制。</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">使用场景</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><code>useEffect</code><span style="color:rgb(15, 17, 21);">：数据请求、订阅、手动修改 DOM 等大部分副作用。</span></li><li><code>useLayoutEffect</code><span style="color:rgb(15, 17, 21);">：需要读取或同步修改 DOM 布局，并希望避免用户看到闪烁的场景（如测量元素尺寸后触发重渲染）。</span></li></ul></li></ul><h3 id="_3-hooks-闭包陷阱是什么" tabindex="-1"><span style="color:rgb(15, 17, 21);">3. hooks 闭包陷阱是什么？</span> <a class="header-anchor" href="#_3-hooks-闭包陷阱是什么" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;3. hooks 闭包陷阱是什么？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">函数每次渲染都会捕获当前的 props 和 state 形成闭包。</span></li><li><span style="color:rgb(15, 17, 21);">当</span><span style="color:rgb(15, 17, 21);"></span><code>useEffect</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">或回调内使用了某状态但未将其加入依赖数组时，该函数内始终引用的是旧渲染时的值（过期闭包）。</span></li><li><span style="color:rgb(15, 17, 21);">典型例子：</span><code>setInterval</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">内引用 state 但依赖数组为空，导致 counter 始终是初始值。</span></li><li><strong><span style="color:rgb(15, 17, 21);">解决</span></strong><span style="color:rgb(15, 17, 21);">：使用函数式更新</span><span style="color:rgb(15, 17, 21);"></span><code>setState(c =&gt; c + 1)</code><span style="color:rgb(15, 17, 21);">、</span><code>useRef</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">保存最新值、或正确声明依赖。</span></li></ul><h3 id="_4-usememo-usecallback-真能优化性能吗" tabindex="-1"><span style="color:rgb(15, 17, 21);">4. useMemo/useCallback 真能优化性能吗？</span> <a class="header-anchor" href="#_4-usememo-usecallback-真能优化性能吗" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;4. useMemo/useCallback 真能优化性能吗？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">能优化的情况</span></strong><span style="color:rgb(15, 17, 21);">：当计算结果被传给深层子组件并用</span><span style="color:rgb(15, 17, 21);"></span><code>React.memo</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">包裹，或作为其他 Hooks 的依赖时，保持引用稳定可避免不必要的子组件重渲染或副作用执行。</span></li><li><strong><span style="color:rgb(15, 17, 21);">带来负担的情况</span></strong><span style="color:rgb(15, 17, 21);">：每次渲染自身需要执行依赖比较和可能的内存缓存维护，对于简单计算或未传递给子组件的值，反而增加开销。</span></li><li><strong><span style="color:rgb(15, 17, 21);">原则</span></strong><span style="color:rgb(15, 17, 21);">：先写清晰代码，有性能瓶颈时再用 Profiler 分析后按需使用。</span></li></ul><h3 id="_5-useref-为什么修改不触发-render" tabindex="-1"><span style="color:rgb(15, 17, 21);">5. useRef 为什么修改不触发 render？</span> <a class="header-anchor" href="#_5-useref-为什么修改不触发-render" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;5. useRef 为什么修改不触发 render？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><code>useRef</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">返回一个普通的 JavaScript 对象</span><span style="color:rgb(15, 17, 21);"></span><code>{ current: ... }</code><span style="color:rgb(15, 17, 21);">。</span></li><li><span style="color:rgb(15, 17, 21);">React 不会对</span><span style="color:rgb(15, 17, 21);"></span><code>ref.current</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">的修改设置任何追踪或 setter，自然也不会触发 re-render。</span></li><li><span style="color:rgb(15, 17, 21);">它的本质是提供一种</span><strong><span style="color:rgb(15, 17, 21);">可跨渲染周期持久化</span></strong><span style="color:rgb(15, 17, 21);">的可变容器，多用于保存 DOM 引用、定时器 ID 等不需要驱动渲染的值。</span></li></ul><h3 id="_6-如何实现一个自定义-hook" tabindex="-1"><span style="color:rgb(15, 17, 21);">6. 如何实现一个自定义 hook？</span> <a class="header-anchor" href="#_6-如何实现一个自定义-hook" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;6. 如何实现一个自定义 hook？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">以</span><span style="color:rgb(15, 17, 21);"></span><code>use</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">开头命名，内部可调用其他 Hooks。</span></li><li><span style="color:rgb(15, 17, 21);">封装可复用的</span><strong><span style="color:rgb(15, 17, 21);">状态逻辑</span></strong><span style="color:rgb(15, 17, 21);">而非 UI，返回所需的状态值或操作方法。</span></li><li><span style="color:rgb(15, 17, 21);">关键点：</span><ul><li><span style="color:rgb(15, 17, 21);">独立的闭包作用域，每个使用自定义 Hook 的组件间状态完全隔离。</span></li><li><span style="color:rgb(15, 17, 21);">遵循 Hooks 规则，确保在顶层调用。</span></li></ul></li><li><span style="color:rgb(15, 17, 21);">例如：</span><code>useWindowSize</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">监听窗口大小变化并返回当前宽高。</span></li></ul><h3 id="_7-hooks-为什么依赖数组容易出-bug" tabindex="-1"><span style="color:rgb(15, 17, 21);">7. hooks 为什么依赖数组容易出 bug？</span> <a class="header-anchor" href="#_7-hooks-为什么依赖数组容易出-bug" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;7. hooks 为什么依赖数组容易出 bug？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">遗漏依赖</span></strong><span style="color:rgb(15, 17, 21);">：使用了某个外部变量但未放入数组，导致使用过期值。</span></li><li><strong><span style="color:rgb(15, 17, 21);">多余依赖</span></strong><span style="color:rgb(15, 17, 21);">：将不稳定的引用（如内联对象、函数）放入依赖，导致死循环或频繁执行。</span></li><li><strong><span style="color:rgb(15, 17, 21);">插件告警</span></strong><span style="color:rgb(15, 17, 21);">：React 官方</span><span style="color:rgb(15, 17, 21);"></span><code>eslint-plugin-react-hooks</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">会提示依赖缺失，开发者忽视告警而直接禁用规则。</span></li><li><strong><span style="color:rgb(15, 17, 21);">心智负担</span></strong><span style="color:rgb(15, 17, 21);">：需要透彻理解闭包和渲染时机，初学者容易犯错。</span></li></ul><h3 id="_8-react-hooks-原理是什么" tabindex="-1"><span style="color:rgb(15, 17, 21);">8. React hooks 原理是什么？</span> <a class="header-anchor" href="#_8-react-hooks-原理是什么" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;8. React hooks 原理是什么？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">每个组件对应一个 Fiber 节点，Fiber 上挂载以</span><strong><span style="color:rgb(15, 17, 21);">链表形式</span></strong><span style="color:rgb(15, 17, 21);">存储的 Hooks 集合。</span></li><li><span style="color:rgb(15, 17, 21);">渲染时，React 维护一个全局的</span><span style="color:rgb(15, 17, 21);"></span><code>currentHook</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">指针，在组件函数执行时按顺序逐个读取/创建 Hook 状态。</span></li><li><span style="color:rgb(15, 17, 21);">每个 Hook 节点存储着自身的状态、更新队列（如</span><span style="color:rgb(15, 17, 21);"></span><code>setState</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">触发的更新）和副作用信息。</span></li><li><span style="color:rgb(15, 17, 21);">状态更新通过调度（dispatch）将 action 推入队列，触发组件重渲染，Hook 会从 Fiber 中还原到最新的状态链表。</span></li></ul><h3 id="_9-如何避免-useeffect-死循环" tabindex="-1"><span style="color:rgb(15, 17, 21);">9. 如何避免 useEffect 死循环？</span> <a class="header-anchor" href="#_9-如何避免-useeffect-死循环" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;9. 如何避免 useEffect 死循环？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">检查依赖</span></strong><span style="color:rgb(15, 17, 21);">：确认依赖数组中的值在每次渲染时是否引用恒定。对象、数组、函数等引用类型若每次渲染都重新创建，会导致死循环。</span></li><li><strong><span style="color:rgb(15, 17, 21);">使用 useMemo/useCallback 稳定引用</span></strong><span style="color:rgb(15, 17, 21);">。</span></li><li><strong><span style="color:rgb(15, 17, 21);">函数式更新</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>setState(prev =&gt; ...)</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">可不依赖外部 state。</span></li><li><strong><span style="color:rgb(15, 17, 21);">移除非必须依赖</span></strong><span style="color:rgb(15, 17, 21);">：尽量在 effect 内部自给自足所需数据。</span></li></ul><h3 id="_10-如何设计复杂-hooks" tabindex="-1"><span style="color:rgb(15, 17, 21);">10. 如何设计复杂 hooks？</span> <a class="header-anchor" href="#_10-如何设计复杂-hooks" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;10. 如何设计复杂 hooks？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">单一职责</span></strong><span style="color:rgb(15, 17, 21);">：一个 Hook 只做一件事，便于测试和组合。</span></li><li><strong><span style="color:rgb(15, 17, 21);">组合优于继承</span></strong><span style="color:rgb(15, 17, 21);">：多个小 Hook 组合成功能强大的 Hook。</span></li><li><strong><span style="color:rgb(15, 17, 21);">清晰的返回接口</span></strong><span style="color:rgb(15, 17, 21);">：返回对象而非数组（当返回值多时），或采用元组风格。</span></li><li><strong><span style="color:rgb(15, 17, 21);">状态管理</span></strong><span style="color:rgb(15, 17, 21);">：复杂逻辑内部使用</span><span style="color:rgb(15, 17, 21);"></span><code>useReducer</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">集中状态变更，而非散落的</span><span style="color:rgb(15, 17, 21);"></span><code>useState</code><span style="color:rgb(15, 17, 21);">。</span></li><li><strong><span style="color:rgb(15, 17, 21);">副作用管理</span></strong><span style="color:rgb(15, 17, 21);">：合理利用依赖，确保清理函数可靠执行，避免内存泄露。</span></li></ul><hr><h2 id="第三部分-react-原理与源码-10题" tabindex="-1"><span style="color:rgb(15, 17, 21);">第三部分：React 原理与源码（10题）</span> <a class="header-anchor" href="#第三部分-react-原理与源码-10题" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;第三部分：React 原理与源码（10题）&lt;/span&gt;&quot;">​</a></h2><h3 id="_1-react-fiber-架构是什么" tabindex="-1"><span style="color:rgb(15, 17, 21);">1. React Fiber 架构是什么？</span> <a class="header-anchor" href="#_1-react-fiber-架构是什么" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;1. React Fiber 架构是什么？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">Fiber 是 React 16 中重新实现的核心调和引擎，它将渲染工作拆分为</span><strong><span style="color:rgb(15, 17, 21);">可中断的小工作单元</span></strong><span style="color:rgb(15, 17, 21);">。</span></li><li><span style="color:rgb(15, 17, 21);">每个 React 元素对应一个 Fiber 节点，构成 Fiber 树，节点中记录组件的类型、状态、待处理更新等信息。</span></li><li><span style="color:rgb(15, 17, 21);">通过</span><strong><span style="color:rgb(15, 17, 21);">时间切片</span></strong><span style="color:rgb(15, 17, 21);">和</span><strong><span style="color:rgb(15, 17, 21);">优先级调度</span></strong><span style="color:rgb(15, 17, 21);">，Fiber 使 React 能够将长时间的任务分散执行，不阻塞主线程，保证界面流畅。</span></li></ul><h3 id="_2-fiber-为什么是链表树" tabindex="-1"><span style="color:rgb(15, 17, 21);">2. Fiber 为什么是链表树？</span> <a class="header-anchor" href="#_2-fiber-为什么是链表树" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;2. Fiber 为什么是链表树？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">链表结构（通过</span><span style="color:rgb(15, 17, 21);"></span><code>child</code><span style="color:rgb(15, 17, 21);">、</span><code>sibling</code><span style="color:rgb(15, 17, 21);">、</span><code>return</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">指针形成）支持</span><strong><span style="color:rgb(15, 17, 21);">单向遍历而不依赖栈</span></strong><span style="color:rgb(15, 17, 21);">。</span></li><li><span style="color:rgb(15, 17, 21);">在可中断渲染中，当前工作进度可以保存在当前 Fiber 节点上，下次恢复时直接从断点继续，无需重新遍历。</span></li><li><span style="color:rgb(15, 17, 21);">传统的递归树结构调用栈深且无法中断，而链表使遍历变得扁平、可暂停。</span></li></ul><h3 id="_3-react-调度机制-scheduler-是什么" tabindex="-1"><span style="color:rgb(15, 17, 21);">3. React 调度机制 scheduler 是什么？</span> <a class="header-anchor" href="#_3-react-调度机制-scheduler-是什么" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;3. React 调度机制 scheduler 是什么？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">Scheduler 是一个独立的包，负责按照优先级调度任务。</span></li><li><span style="color:rgb(15, 17, 21);">利用浏览器的</span><span style="color:rgb(15, 17, 21);"></span><code>MessageChannel</code><span style="color:rgb(15, 17, 21);">（或</span><span style="color:rgb(15, 17, 21);"></span><code>requestIdleCallback</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">的 polyfill）实现</span><strong><span style="color:rgb(15, 17, 21);">宏任务级的异步调度</span></strong><span style="color:rgb(15, 17, 21);">，在每帧绘制前的空闲时间执行低优先级的 React 更新。</span></li><li><span style="color:rgb(15, 17, 21);">通过</span><span style="color:rgb(15, 17, 21);"></span><code>unstable_scheduleCallback</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">将任务排队，根据过期时间和优先级决定执行顺序，支持暂停、终止和恢复。</span></li></ul><h3 id="_4-render-阶段与-commit-阶段区别" tabindex="-1"><span style="color:rgb(15, 17, 21);">4. Render 阶段与 Commit 阶段区别？</span> <a class="header-anchor" href="#_4-render-阶段与-commit-阶段区别" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;4. Render 阶段与 Commit 阶段区别？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">Render 阶段</span></strong><span style="color:rgb(15, 17, 21);">（可中断）：</span><ul><li><span style="color:rgb(15, 17, 21);">遍历 Fiber 树，对比新旧节点（Diff），计算需要变更的 effect（增、删、改）。</span></li><li><span style="color:rgb(15, 17, 21);">纯计算，无可见 DOM 变更，可被更高优先级任务打断。</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">Commit 阶段</span></strong><span style="color:rgb(15, 17, 21);">（不可中断）：</span><ul><li><span style="color:rgb(15, 17, 21);">将 Render 阶段计算出的 effect 列表应用到真实 DOM。</span></li><li><span style="color:rgb(15, 17, 21);">分为</span><span style="color:rgb(15, 17, 21);"></span><code>before mutation</code><span style="color:rgb(15, 17, 21);">（执行</span><span style="color:rgb(15, 17, 21);"></span><code>getSnapshotBeforeUpdate</code><span style="color:rgb(15, 17, 21);">）、</span><code>mutation</code><span style="color:rgb(15, 17, 21);">（DOM 变更）、</span><code>layout</code><span style="color:rgb(15, 17, 21);">（执行</span><span style="color:rgb(15, 17, 21);"></span><code>useLayoutEffect</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">的销毁和创建）三个子阶段。</span></li><li><span style="color:rgb(15, 17, 21);">必须同步一次性执行，保证界面一致性。</span></li></ul></li></ul><h3 id="_5-react-diff-为什么是-o-n" tabindex="-1"><span style="color:rgb(15, 17, 21);">5. React Diff 为什么是 O(n)？</span> <a class="header-anchor" href="#_5-react-diff-为什么是-o-n" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;5. React Diff 为什么是 O(n)？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">基于三条前提假设，将算法复杂度从通用的 O(n³) 降至 O(n)：</span><ol><li><span style="color:rgb(15, 17, 21);">只对同级元素比较，跨层级忽略</span></li><li><span style="color:rgb(15, 17, 21);">不同类型的组件生成不同的树</span></li><li><span style="color:rgb(15, 17, 21);">通过</span><span style="color:rgb(15, 17, 21);"></span><code>key</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">追踪同层级子元素</span></li></ol></li><li><span style="color:rgb(15, 17, 21);">实际只遍历一遍节点列表即可完成对比。</span></li></ul><h3 id="_6-react-双缓存树是什么" tabindex="-1"><span style="color:rgb(15, 17, 21);">6. React 双缓存树是什么？</span> <a class="header-anchor" href="#_6-react-双缓存树是什么" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;6. React 双缓存树是什么？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">React 维护两棵 Fiber 树：</span><ul><li><strong><span style="color:rgb(15, 17, 21);">Current 树</span></strong><span style="color:rgb(15, 17, 21);">：对应当前屏幕上显示的内容。</span></li><li><strong><span style="color:rgb(15, 17, 21);">WorkInProgress 树</span></strong><span style="color:rgb(15, 17, 21);">：正在内存中构建的新树，用于计算下一次渲染。</span></li></ul></li><li><span style="color:rgb(15, 17, 21);">更新时，React 在 WorkInProgress 树上进行 Diff 和变更，完成后直接将</span><span style="color:rgb(15, 17, 21);"></span><code>current</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">指针切换过去（切换根节点），旧树成为下一次的缓存，避免了创建大量新对象的开销。</span></li></ul><h3 id="_7-react-为什么不能跨层复用节点" tabindex="-1"><span style="color:rgb(15, 17, 21);">7. React 为什么不能跨层复用节点？</span> <a class="header-anchor" href="#_7-react-为什么不能跨层复用节点" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;7. React 为什么不能跨层复用节点？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">从 Diff 算法策略看，React 假设跨层移动极为少见。</span></li><li><span style="color:rgb(15, 17, 21);">若允许跨层复用，需要对比不同层级、不同父节点的子树，复杂度会上升到不可接受的程度。</span></li><li><span style="color:rgb(15, 17, 21);">架构上，Fiber 节点通过</span><span style="color:rgb(15, 17, 21);"></span><code>return</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">指向父节点，跨层移动意味大量节点需要重新链接，反而可能比销毁重建更昂贵。</span></li><li><span style="color:rgb(15, 17, 21);">因此面对跨层移动，React 选择</span><strong><span style="color:rgb(15, 17, 21);">原地销毁并重建</span></strong><span style="color:rgb(15, 17, 21);">，符合性能权衡。</span></li></ul><h3 id="_8-concurrent-rendering-是什么" tabindex="-1"><span style="color:rgb(15, 17, 21);">8. Concurrent Rendering 是什么？</span> <a class="header-anchor" href="#_8-concurrent-rendering-是什么" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;8. Concurrent Rendering 是什么？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">并发渲染是 React 18 引入的新特性集合，让 React 能同时准备多个版本的 UI，根据优先级进行中断、暂停或丢弃。</span></li><li><span style="color:rgb(15, 17, 21);">依赖于</span><span style="color:rgb(15, 17, 21);"></span><code>createRoot</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">和</span><span style="color:rgb(15, 17, 21);"></span><code>useTransition</code><span style="color:rgb(15, 17, 21);">、</span><code>useDeferredValue</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">等 API。</span></li><li><span style="color:rgb(15, 17, 21);">优势：允许高优先级更新（如用户输入）打断低优先级的渲染（如大数据列表），保持界面响应流畅。</span></li></ul><h3 id="_9-react18-自动批处理原理" tabindex="-1"><span style="color:rgb(15, 17, 21);">9. React18 自动批处理原理？</span> <a class="header-anchor" href="#_9-react18-自动批处理原理" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;9. React18 自动批处理原理？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">在 React 18 中，使用</span><span style="color:rgb(15, 17, 21);"></span><code>createRoot</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">挂载的应用会开启自动批处理。</span></li><li><span style="color:rgb(15, 17, 21);">React 内部维护一个批处理标志，在调用</span><span style="color:rgb(15, 17, 21);"></span><code>setState</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">时将其放入更新队列，待当前执行环境结束（如事件处理、setTimeout、Promise 回调）后，通过调度机制一次性地清空队列并执行渲染。</span></li><li><span style="color:rgb(15, 17, 21);">而 React 17 只在浏览器事件和生命周期中开启批处理，异步环境中多次</span><span style="color:rgb(15, 17, 21);"></span><code>setState</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">会分别触发渲染。18 通过增强调度器覆盖了更多场景。</span></li></ul><h3 id="_10-react18-的-lane-模型是什么" tabindex="-1"><span style="color:rgb(15, 17, 21);">10. React18 的 Lane 模型是什么？</span> <a class="header-anchor" href="#_10-react18-的-lane-模型是什么" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;10. React18 的 Lane 模型是什么？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">Lane 是 React 中表示更新优先级的</span><strong><span style="color:rgb(15, 17, 21);">位掩码模型</span></strong><span style="color:rgb(15, 17, 21);">，取代了旧的 Expiration Time 模型。</span></li><li><span style="color:rgb(15, 17, 21);">每个更新被分配一个或多个 Lane，不同 Lane 表示不同优先级和类别（如同步、默认、空闲、过渡等）。</span></li><li><span style="color:rgb(15, 17, 21);">通过位运算可以快速</span><strong><span style="color:rgb(15, 17, 21);">合并、区分和判断</span></strong><span style="color:rgb(15, 17, 21);">优先级的包含关系，能更灵活地处理多个更新间的批处理、饥饿问题（低优先级更新长期不被执行）以及中断恢复。</span></li></ul><hr><h2 id="第四部分-react-性能优化-8题" tabindex="-1"><span style="color:rgb(15, 17, 21);">第四部分：React 性能优化（8题）</span> <a class="header-anchor" href="#第四部分-react-性能优化-8题" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;第四部分：React 性能优化（8题）&lt;/span&gt;&quot;">​</a></h2><h3 id="_1-react-性能优化方案有哪些" tabindex="-1"><span style="color:rgb(15, 17, 21);">1. React 性能优化方案有哪些？</span> <a class="header-anchor" href="#_1-react-性能优化方案有哪些" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;1. React 性能优化方案有哪些？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">组件层面</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>React.memo</code><span style="color:rgb(15, 17, 21);">、</span><code>PureComponent</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">避免不必要渲染。</span></li><li><strong><span style="color:rgb(15, 17, 21);">Hooks</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>useMemo</code><span style="color:rgb(15, 17, 21);">、</span><code>useCallback</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">缓存计算结果和函数引用。</span></li><li><strong><span style="color:rgb(15, 17, 21);">数据层面</span></strong><span style="color:rgb(15, 17, 21);">：状态下移、状态提升合理拆分，避免大范围重渲染；使用不可变数据简化比较。</span></li><li><strong><span style="color:rgb(15, 17, 21);">渲染层面</span></strong><span style="color:rgb(15, 17, 21);">：虚拟列表（</span><code>react-window</code><span style="color:rgb(15, 17, 21);">）渲染大列表；懒加载图片和组件。</span></li><li><strong><span style="color:rgb(15, 17, 21);">加载层面</span></strong><span style="color:rgb(15, 17, 21);">：代码分割（</span><code>React.lazy</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">+ Suspense）、路由懒加载。</span></li><li><strong><span style="color:rgb(15, 17, 21);">工具</span></strong><span style="color:rgb(15, 17, 21);">：使用 Profiler 和 React DevTools 定位瓶颈。</span></li></ul><h3 id="_2-react-memo-原理" tabindex="-1"><span style="color:rgb(15, 17, 21);">2. React.memo 原理？</span> <a class="header-anchor" href="#_2-react-memo-原理" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;2. React.memo 原理？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><code>React.memo</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">是一个高阶组件，对组件的</span><span style="color:rgb(15, 17, 21);"></span><code>props</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">进行</span><strong><span style="color:rgb(15, 17, 21);">浅比较</span></strong><span style="color:rgb(15, 17, 21);">，如果 props 未变化则跳过渲染直接复用上次结果。</span></li><li><span style="color:rgb(15, 17, 21);">原理类似于类组件的</span><span style="color:rgb(15, 17, 21);"></span><code>PureComponent</code><span style="color:rgb(15, 17, 21);">，但可传入自定义比较函数作为第二个参数，进行深比较或特定规则判断。</span></li><li><span style="color:rgb(15, 17, 21);">若父组件渲染但传给子组件的 props 引用相同，</span><code>React.memo</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">能有效阻断渲染链。</span></li></ul><h3 id="_3-大列表如何优化" tabindex="-1"><span style="color:rgb(15, 17, 21);">3. 大列表如何优化？</span> <a class="header-anchor" href="#_3-大列表如何优化" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;3. 大列表如何优化？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">虚拟列表（Windowing）</span></strong><span style="color:rgb(15, 17, 21);">：只渲染可视区域内的元素，大幅减少 DOM 节点数量。常用库</span><span style="color:rgb(15, 17, 21);"></span><code>react-window</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">或</span><span style="color:rgb(15, 17, 21);"></span><code>react-virtualized</code><span style="color:rgb(15, 17, 21);">。</span></li><li><strong><span style="color:rgb(15, 17, 21);">缓存项高度</span></strong><span style="color:rgb(15, 17, 21);">：若列表项高度不固定，需动态测算，可缓存计算结果。</span></li><li><strong><span style="color:rgb(15, 17, 21);">防抖/节流</span></strong><span style="color:rgb(15, 17, 21);">：对于滚动事件的频繁更新进行限流。</span></li><li><strong><span style="color:rgb(15, 17, 21);">惰性加载</span></strong><span style="color:rgb(15, 17, 21);">：图片采用</span><span style="color:rgb(15, 17, 21);"></span><code>Intersection Observer</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">实现懒加载。</span></li></ul><h3 id="_4-react-为什么会重复-render" tabindex="-1"><span style="color:rgb(15, 17, 21);">4. React 为什么会重复 render？</span> <a class="header-anchor" href="#_4-react-为什么会重复-render" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;4. React 为什么会重复 render？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">父组件渲染导致子组件渲染</span></strong><span style="color:rgb(15, 17, 21);">（默认行为，即使子组件 props 未变）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">Context 变化</span></strong><span style="color:rgb(15, 17, 21);">，所有消费该 Context 的组件都会更新。</span></li><li><strong><span style="color:rgb(15, 17, 21);">匿名函数或内联对象作为 props</span></strong><span style="color:rgb(15, 17, 21);">，每次渲染引用均变化，即使</span><span style="color:rgb(15, 17, 21);"></span><code>React.memo</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">也会失效。</span></li><li><strong><span style="color:rgb(15, 17, 21);">Hooks 依赖变化</span></strong><span style="color:rgb(15, 17, 21);">，或状态更新（即使值相同，</span><code>setState</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">也会触发渲染，但 React 可能在调度期跳过）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">全局状态库</span></strong><span style="color:rgb(15, 17, 21);">（如 Redux）连接的组件，当状态切片变化时更新。</span></li></ul><h3 id="_5-context-为什么可能性能差" tabindex="-1"><span style="color:rgb(15, 17, 21);">5. Context 为什么可能性能差？</span> <a class="header-anchor" href="#_5-context-为什么可能性能差" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;5. Context 为什么可能性能差？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">Context 值一旦变化，</span><strong><span style="color:rgb(15, 17, 21);">所有消费者</span></strong><span style="color:rgb(15, 17, 21);">都会重新渲染，不受</span><span style="color:rgb(15, 17, 21);"></span><code>React.memo</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">或</span><span style="color:rgb(15, 17, 21);"></span><code>shouldComponentUpdate</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">影响。</span></li><li><span style="color:rgb(15, 17, 21);">若 Context 持有的是一个宽泛的大对象，任何细小的属性变更都会引发全局渲染。</span></li><li><span style="color:rgb(15, 17, 21);">优化方式：拆分 Context（按主题、用户、配置等）、保持 value 引用稳定（</span><code>useMemo</code><span style="color:rgb(15, 17, 21);">）、使用</span><span style="color:rgb(15, 17, 21);"></span><code>useContextSelector</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">模式的库（如 zustand、jotai）来订阅局部状态。</span></li></ul><h3 id="_6-如何做代码分割" tabindex="-1"><span style="color:rgb(15, 17, 21);">6. 如何做代码分割？</span> <a class="header-anchor" href="#_6-如何做代码分割" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;6. 如何做代码分割？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">使用动态</span><span style="color:rgb(15, 17, 21);"></span><code>import()</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">语法结合</span><span style="color:rgb(15, 17, 21);"></span><code>React.lazy</code><span style="color:rgb(15, 17, 21);">。</span></li><li><span style="color:rgb(15, 17, 21);">示例：</span><code>const LazyComp = React.lazy(() =&gt; import(&#39;./Comp&#39;));</code></li><li><span style="color:rgb(15, 17, 21);">用</span><span style="color:rgb(15, 17, 21);"></span><code>Suspense</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">包裹，提供加载中的 fallback UI。</span></li><li><span style="color:rgb(15, 17, 21);">在路由层面进行分割是最佳实践：每个页面对应一个独立的 chunk。</span></li><li><span style="color:rgb(15, 17, 21);">可配置 Webpack 的分包策略（SplitChunksPlugin）提取公共库、按需加载。</span></li></ul><h3 id="_7-suspense-的作用" tabindex="-1"><span style="color:rgb(15, 17, 21);">7. Suspense 的作用？</span> <a class="header-anchor" href="#_7-suspense-的作用" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;7. Suspense 的作用？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">提供一种声明式的方式来处理异步操作（如代码加载、数据获取）的加载状态。</span></li><li><strong><span style="color:rgb(15, 17, 21);">代码分割场景</span></strong><span style="color:rgb(15, 17, 21);">：配合</span><span style="color:rgb(15, 17, 21);"></span><code>React.lazy</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">展示加载指示器。</span></li><li><strong><span style="color:rgb(15, 17, 21);">数据获取场景</span></strong><span style="color:rgb(15, 17, 21);">（实验性/未来主流）：组件可直接“挂起”，等待数据 Ready，配合 React 18 的并发特性（如</span><span style="color:rgb(15, 17, 21);"></span><code>use</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">hook、Relay 等）。</span></li><li><span style="color:rgb(15, 17, 21);">可嵌套，提供更细粒度的加载控制。</span></li></ul><h3 id="_8-ssr-如何优化首屏" tabindex="-1"><span style="color:rgb(15, 17, 21);">8. SSR 如何优化首屏？</span> <a class="header-anchor" href="#_8-ssr-如何优化首屏" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;8. SSR 如何优化首屏？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">流式渲染（Streaming）</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>renderToPipeableStream</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">允许尽早向客户端发送 HTML 片段，不必等待全部内容生成。</span></li><li><strong><span style="color:rgb(15, 17, 21);">选择性注水（Selective Hydration）</span></strong><span style="color:rgb(15, 17, 21);">：React 18 支持优先注水用户交互的部分（如用</span><span style="color:rgb(15, 17, 21);"></span><code>Suspense</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">包裹），其余部分延迟注水。</span></li><li><strong><span style="color:rgb(15, 17, 21);">组件级数据预取</span></strong><span style="color:rgb(15, 17, 21);">：避免全局阻塞，在路由层并行请求数据。</span></li><li><strong><span style="color:rgb(15, 17, 21);">缓存</span></strong><span style="color:rgb(15, 17, 21);">：CDN 缓存 SSR 结果、组件级缓存。</span></li><li><strong><span style="color:rgb(15, 17, 21);">关键 CSS 内联</span></strong><span style="color:rgb(15, 17, 21);">，减少外部资源阻塞渲染。</span></li></ul><hr><h2 id="第五部分-架构与场景题-10题" tabindex="-1"><span style="color:rgb(15, 17, 21);">第五部分：架构与场景题（10题）</span> <a class="header-anchor" href="#第五部分-架构与场景题-10题" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;第五部分：架构与场景题（10题）&lt;/span&gt;&quot;">​</a></h2><h3 id="_1-如何设计一个高性能表单系统" tabindex="-1"><span style="color:rgb(15, 17, 21);">1. 如何设计一个高性能表单系统？</span> <a class="header-anchor" href="#_1-如何设计一个高性能表单系统" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;1. 如何设计一个高性能表单系统？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">架构分层</span></strong><span style="color:rgb(15, 17, 21);">：核心层（状态管理、校验引擎）、UI 层（受控组件）、联动层。</span></li><li><strong><span style="color:rgb(15, 17, 21);">状态管理</span></strong><span style="color:rgb(15, 17, 21);">：使用专用表单库（如 React Hook Form）实现非受控模式，避免每次输入都触发整个表单重渲染；利用</span><span style="color:rgb(15, 17, 21);"></span><code>ref</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">收集数据，仅在提交时校验。</span></li><li><strong><span style="color:rgb(15, 17, 21);">校验系统</span></strong><span style="color:rgb(15, 17, 21);">：支持声明式规则和自定义校验函数，异步校验节流，展示即时错误信息。</span></li><li><strong><span style="color:rgb(15, 17, 21);">动态字段</span></strong><span style="color:rgb(15, 17, 21);">：通过</span><span style="color:rgb(15, 17, 21);"></span><code>useFieldArray</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">管理动态增删，保持每个字段的性能隔离。</span></li><li><strong><span style="color:rgb(15, 17, 21);">依赖联动</span></strong><span style="color:rgb(15, 17, 21);">：定义字段间依赖关系，采用高效订阅机制，局部更新。</span></li></ul><h3 id="_2-react-权限系统如何设计" tabindex="-1"><span style="color:rgb(15, 17, 21);">2. React 权限系统如何设计？</span> <a class="header-anchor" href="#_2-react-权限系统如何设计" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;2. React 权限系统如何设计？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">权限定义</span></strong><span style="color:rgb(15, 17, 21);">：前端维护菜单权限、按钮权限、路由权限等，通常由后端接口下发。</span></li><li><strong><span style="color:rgb(15, 17, 21);">路由权限</span></strong><span style="color:rgb(15, 17, 21);">：在路由配置中加入</span><span style="color:rgb(15, 17, 21);"></span><code>auth</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">或</span><span style="color:rgb(15, 17, 21);"></span><code>roles</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">字段，动态生成可访问路由表。</span></li><li><strong><span style="color:rgb(15, 17, 21);">组件封装</span></strong><span style="color:rgb(15, 17, 21);">：实现</span><span style="color:rgb(15, 17, 21);"></span><code>&lt;Auth&gt;</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">组件，传入所需权限标识，内部比对用户权限决定是否渲染子元素。</span></li><li><strong><span style="color:rgb(15, 17, 21);">指令式</span></strong><span style="color:rgb(15, 17, 21);">：自定义 Hook</span><span style="color:rgb(15, 17, 21);"></span><code>useAuth(&#39;perm&#39;)</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">返回布尔值进行逻辑控制。</span></li><li><strong><span style="color:rgb(15, 17, 21);">更新机制</span></strong><span style="color:rgb(15, 17, 21);">：权限数据通过 Context 或状态管理全局存储，登录/切换账号后刷新。</span></li></ul><h3 id="_3-微前端在-react-怎么落地" tabindex="-1"><span style="color:rgb(15, 17, 21);">3. 微前端在 React 怎么落地？</span> <a class="header-anchor" href="#_3-微前端在-react-怎么落地" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;3. 微前端在 React 怎么落地？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">框架选择</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>qiankun</code><span style="color:rgb(15, 17, 21);">（基于 single-spa）、</span><code>Micro-app</code><span style="color:rgb(15, 17, 21);">、</span><code>Module Federation</code><span style="color:rgb(15, 17, 21);">（Webpack 5）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">基座与子应用</span></strong><span style="color:rgb(15, 17, 21);">：基座负责路由分发、权限验证、全局状态，子应用独立部署。</span></li><li><strong><span style="color:rgb(15, 17, 21);">隔离</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><span style="color:rgb(15, 17, 21);">JS 隔离：沙箱（Proxy 或快照）防止全局变量污染。</span></li><li><span style="color:rgb(15, 17, 21);">样式隔离：CSS Modules、Shadow DOM、前缀约定。</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">通信</span></strong><span style="color:rgb(15, 17, 21);">：自定义事件（</span><code>CustomEvent</code><span style="color:rgb(15, 17, 21);">）、基座下发的公共 API、shared 状态管理（如将 store 注入子应用）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">共享依赖</span></strong><span style="color:rgb(15, 17, 21);">：通过</span><span style="color:rgb(15, 17, 21);"></span><code>externals</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">或 Module Federation 共享 React、ReactDOM 等库。</span></li></ul><h3 id="_4-react-状态管理怎么选" tabindex="-1"><span style="color:rgb(15, 17, 21);">4. React 状态管理怎么选？</span> <a class="header-anchor" href="#_4-react-状态管理怎么选" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;4. React 状态管理怎么选？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">简单场景</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>useState</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">+</span><span style="color:rgb(15, 17, 21);"></span><code>useContext</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">即可。</span></li><li><strong><span style="color:rgb(15, 17, 21);">中等复杂度、需要中间件</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>Redux Toolkit</code><span style="color:rgb(15, 17, 21);">（标准化、DevTools 强、生态大）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">响应式/可变数据</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>MobX</code><span style="color:rgb(15, 17, 21);">（样板少，OOP 友好）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">轻量高性能</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>Zustand</code><span style="color:rgb(15, 17, 21);">（无 Provider 包裹，按需订阅）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">原子化状态</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>Jotai</code><span style="color:rgb(15, 17, 21);">、</span><code>Recoil</code><span style="color:rgb(15, 17, 21);">（细粒度更新，避免额外渲染）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">选型依据</span></strong><span style="color:rgb(15, 17, 21);">：团队熟练度、项目体积、性能需求、数据流复杂度。</span></li></ul><h3 id="_5-如何设计低代码组件体系" tabindex="-1"><span style="color:rgb(15, 17, 21);">5. 如何设计低代码组件体系？</span> <a class="header-anchor" href="#_5-如何设计低代码组件体系" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;5. 如何设计低代码组件体系？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">组件协议</span></strong><span style="color:rgb(15, 17, 21);">：定义统一的组件 Schema（类型、props、事件、样式、插槽）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">物料库</span></strong><span style="color:rgb(15, 17, 21);">：按分类组织，每个物料组件需有渲染器和配置器。</span></li><li><strong><span style="color:rgb(15, 17, 21);">渲染引擎</span></strong><span style="color:rgb(15, 17, 21);">：解析 JSON Schema，递归渲染物料组件并绑定数据和事件。</span></li><li><strong><span style="color:rgb(15, 17, 21);">状态与数据源</span></strong><span style="color:rgb(15, 17, 21);">：分离视图模型，支持 API 数据绑定、变量系统、联动逻辑。</span></li><li><strong><span style="color:rgb(15, 17, 21);">扩展机制</span></strong><span style="color:rgb(15, 17, 21);">：支持注册第三方组件，通过插件系统扩展功能，保持核心引擎稳定。</span></li></ul><h3 id="_6-react-大型项目目录怎么设计" tabindex="-1"><span style="color:rgb(15, 17, 21);">6. React 大型项目目录怎么设计？</span> <a class="header-anchor" href="#_6-react-大型项目目录怎么设计" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;6. React 大型项目目录怎么设计？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">按功能/特性分模块</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>features/</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">下每个模块包含自己的</span><span style="color:rgb(15, 17, 21);"></span><code>components</code><span style="color:rgb(15, 17, 21);">、</span><code>hooks</code><span style="color:rgb(15, 17, 21);">、</span><code>api</code><span style="color:rgb(15, 17, 21);">、</span><code>types</code><span style="color:rgb(15, 17, 21);">、</span><code>store</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">等。</span></li><li><strong><span style="color:rgb(15, 17, 21);">共享层</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>components/</code><span style="color:rgb(15, 17, 21);">（通用 UI 组件）、</span><code>hooks/</code><span style="color:rgb(15, 17, 21);">、</span><code>utils/</code><span style="color:rgb(15, 17, 21);">、</span><code>services/</code><span style="color:rgb(15, 17, 21);">（HTTP 封装）、</span><code>styles/</code><span style="color:rgb(15, 17, 21);">。</span></li><li><strong><span style="color:rgb(15, 17, 21);">路由</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>routes/</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">集中配置，结合权限和懒加载。</span></li><li><strong><span style="color:rgb(15, 17, 21);">状态管理</span></strong><span style="color:rgb(15, 17, 21);">：按模块分 slice，在</span><span style="color:rgb(15, 17, 21);"></span><code>store/</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">中聚合。</span></li><li><strong><span style="color:rgb(15, 17, 21);">适配器</span></strong><span style="color:rgb(15, 17, 21);">：API 接口类型定义在</span><span style="color:rgb(15, 17, 21);"></span><code>types/</code><span style="color:rgb(15, 17, 21);">，数据转换在 adapter 层完成，业务逻辑与接口结构解耦。</span></li></ul><h3 id="_7-如何实现-react-埋点系统" tabindex="-1"><span style="color:rgb(15, 17, 21);">7. 如何实现 React 埋点系统？</span> <a class="header-anchor" href="#_7-如何实现-react-埋点系统" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;7. 如何实现 React 埋点系统？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">设计模式</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><strong><span style="color:rgb(15, 17, 21);">声明式埋点</span></strong><span style="color:rgb(15, 17, 21);">：封装</span><span style="color:rgb(15, 17, 21);"></span><code>&lt;Track&gt;</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">组件或</span><span style="color:rgb(15, 17, 21);"></span><code>data-track</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">属性，在组件挂载/卸载/点击时上报。</span></li><li><strong><span style="color:rgb(15, 17, 21);">命令式埋点</span></strong><span style="color:rgb(15, 17, 21);">：提供</span><span style="color:rgb(15, 17, 21);"></span><code>tracker.send(event, data)</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">方法，在业务逻辑中显式调用。</span></li><li><strong><span style="color:rgb(15, 17, 21);">自动埋点</span></strong><span style="color:rgb(15, 17, 21);">：路由切换、页面停留时长、全局异常等可自动采集。</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">实现</span></strong><span style="color:rgb(15, 17, 21);">：利用自定义 Hooks（</span><code>useTracker</code><span style="color:rgb(15, 17, 21);">）、高阶组件（</span><code>withTracking</code><span style="color:rgb(15, 17, 21);">）或自定义事件系统。</span></li><li><strong><span style="color:rgb(15, 17, 21);">解耦</span></strong><span style="color:rgb(15, 17, 21);">：使用 Context 注入上报实例，业务组件无感知具体的上报逻辑（如发送到 GA、自建后台）。</span></li></ul><h3 id="_8-react-国际化方案" tabindex="-1"><span style="color:rgb(15, 17, 21);">8. React 国际化方案？</span> <a class="header-anchor" href="#_8-react-国际化方案" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;8. React 国际化方案？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">库</span></strong><span style="color:rgb(15, 17, 21);">：</span><code>react-intl</code><span style="color:rgb(15, 17, 21);">、</span><code>react-i18next</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">等。</span></li><li><strong><span style="color:rgb(15, 17, 21);">文案管理</span></strong><span style="color:rgb(15, 17, 21);">：提取文案到 JSON/YAML 文件，按语言分包，支持变量和复数规则。</span></li><li><strong><span style="color:rgb(15, 17, 21);">动态加载</span></strong><span style="color:rgb(15, 17, 21);">：按需加载语言包，配合 Code Splitting 减少首次加载量。</span></li><li><strong><span style="color:rgb(15, 17, 21);">切换体验</span></strong><span style="color:rgb(15, 17, 21);">：使用 Context 或状态管理存储当前语言，切换时刷新所有依赖文案的组件，需处理消息的即时替换。</span></li></ul><h3 id="_9-react-如何实现动态主题" tabindex="-1"><span style="color:rgb(15, 17, 21);">9. React 如何实现动态主题？</span> <a class="header-anchor" href="#_9-react-如何实现动态主题" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;9. React 如何实现动态主题？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">CSS Variables</span></strong><span style="color:rgb(15, 17, 21);">：定义 CSS 变量集（颜色、间距等），通过 JavaScript 修改根元素的变量值实现全局切换。</span></li><li><strong><span style="color:rgb(15, 17, 21);">Context 分发</span></strong><span style="color:rgb(15, 17, 21);">：在 ThemeContext 中存储主题配置，提供给组件使用。</span></li><li><strong><span style="color:rgb(15, 17, 21);">CSS-in-JS</span></strong><span style="color:rgb(15, 17, 21);">：如</span><span style="color:rgb(15, 17, 21);"></span><code>styled-components</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">的</span><span style="color:rgb(15, 17, 21);"></span><code>ThemeProvider</code><span style="color:rgb(15, 17, 21);">，按需传入主题对象。</span></li><li><strong><span style="color:rgb(15, 17, 21);">运行时与编译时结合</span></strong><span style="color:rgb(15, 17, 21);">：部分主题可在编译时通过 Less/Sass 变量生成多套样式，运行时只做微调。</span></li></ul><h3 id="_10-react-electron-如何通信" tabindex="-1"><span style="color:rgb(15, 17, 21);">10. React + Electron 如何通信？</span> <a class="header-anchor" href="#_10-react-electron-如何通信" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;10. React + Electron 如何通信？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">渲染进程使用</span><span style="color:rgb(15, 17, 21);"></span><code>window.electronAPI</code><span style="color:rgb(15, 17, 21);">（通过 preload 脚本暴露的</span><span style="color:rgb(15, 17, 21);"></span><code>contextBridge</code><span style="color:rgb(15, 17, 21);">）调用主进程方法。</span></li><li><strong><span style="color:rgb(15, 17, 21);">模式</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><code>ipcRenderer.invoke</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">/</span><span style="color:rgb(15, 17, 21);"></span><code>ipcMain.handle</code><span style="color:rgb(15, 17, 21);">（双向异步，基于 Promise）</span></li><li><code>ipcRenderer.send</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">/</span><span style="color:rgb(15, 17, 21);"></span><code>ipcMain.on</code><span style="color:rgb(15, 17, 21);">（单向消息）</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">安全</span></strong><span style="color:rgb(15, 17, 21);">：预加载脚本中严格控制暴露的 API，避免直接暴露</span><span style="color:rgb(15, 17, 21);"></span><code>ipcRenderer</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">给渲染进程。</span></li><li><strong><span style="color:rgb(15, 17, 21);">状态同步</span></strong><span style="color:rgb(15, 17, 21);">：可通过主进程作为中介，实现多窗口之间的状态同步。</span></li></ul><h3 id="_11-react-项目如何做监控" tabindex="-1"><span style="color:rgb(15, 17, 21);">11. React 项目如何做监控？</span> <a class="header-anchor" href="#_11-react-项目如何做监控" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;11. React 项目如何做监控？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><strong><span style="color:rgb(15, 17, 21);">错误监控</span></strong><span style="color:rgb(15, 17, 21);">：全局</span><span style="color:rgb(15, 17, 21);"></span><code>Error Boundary</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">捕获渲染错误；</span><code>window.onerror</code><span style="color:rgb(15, 17, 21);">、</span><code>unhandledrejection</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">捕获 JS 错误。</span></li><li><strong><span style="color:rgb(15, 17, 21);">性能监控</span></strong><span style="color:rgb(15, 17, 21);">：Web Vitals（LCP、FID、CLS），利用</span><span style="color:rgb(15, 17, 21);"></span><code>web-vitals</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">库，或 React Profiler 记录组件渲染耗时。</span></li><li><strong><span style="color:rgb(15, 17, 21);">接口监控</span></strong><span style="color:rgb(15, 17, 21);">：在 axios/fetch 封装层统一监听请求耗时、状态码、错误。</span></li><li><strong><span style="color:rgb(15, 17, 21);">用户行为</span></strong><span style="color:rgb(15, 17, 21);">：路由跳转、操作链路跟踪。</span></li><li><strong><span style="color:rgb(15, 17, 21);">上报</span></strong><span style="color:rgb(15, 17, 21);">：聚合后通过</span><span style="color:rgb(15, 17, 21);"></span><code>sendBeacon</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">或图片打点上报至自建或第三方平台（Sentry、ARMS）。</span></li></ul><h3 id="_12-react-项目如何做错误边界" tabindex="-1"><span style="color:rgb(15, 17, 21);">12. React 项目如何做错误边界？</span> <a class="header-anchor" href="#_12-react-项目如何做错误边界" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;12. React 项目如何做错误边界？&lt;/span&gt;&quot;">​</a></h3><p><strong><span style="color:rgb(15, 17, 21);">答案：</span></strong></p><ul><li><span style="color:rgb(15, 17, 21);">实现</span><span style="color:rgb(15, 17, 21);"></span><code>componentDidCatch(error, errorInfo)</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">和</span><span style="color:rgb(15, 17, 21);"></span><code>static getDerivedStateFromError(error)</code><span style="color:rgb(15, 17, 21);">。</span></li><li><span style="color:rgb(15, 17, 21);">错误边界是一个类组件，用于捕获子组件树的渲染错误，并在 UI 上显示降级界面，防止整个应用白屏。</span></li><li><strong><span style="color:rgb(15, 17, 21);">局限</span></strong><span style="color:rgb(15, 17, 21);">：</span><ul><li><span style="color:rgb(15, 17, 21);">无法捕获自身错误、事件处理函数错误、异步代码错误（Promise）、SSR 错误。</span></li><li><span style="color:rgb(15, 17, 21);">事件处理和异步错误需配合</span><span style="color:rgb(15, 17, 21);"></span><code>window.onerror</code><span style="color:rgb(15, 17, 21);"></span><span style="color:rgb(15, 17, 21);">/</span><span style="color:rgb(15, 17, 21);"></span><code>try-catch</code><span style="color:rgb(15, 17, 21);">。</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">最佳实践</span></strong><span style="color:rgb(15, 17, 21);">：在应用顶层包裹一个通用 </span><code>ErrorBoundary</code><span style="color:rgb(15, 17, 21);">，并为关键功能区（如侧边栏、主内容区）设置独立的错误边界，使局部错误不影响其他区域。</span></li></ul>',158)])])}const d=o(n,[["render",t]]);export{i as __pageData,d as default};
